class Solution:
    def minCost(self, grid, k):
        m, n = len(grid), len(grid[0])
        INF = float('inf')
        # dp[t] computed via Bellman-style repeated relaxation (no prefix-min trick)
        # layer 0
        def grid_relax(start):
            dp = [row[:] for row in start]
            for i in range(m):
                for j in range(n):
                    if i > 0:
                        dp[i][j] = min(dp[i][j], dp[i - 1][j] + grid[i][j])
                    if j > 0:
                        dp[i][j] = min(dp[i][j], dp[i][j - 1] + grid[i][j])
            return dp
        base = [[INF] * n for _ in range(m)]
        base[0][0] = 0
        layer = grid_relax(base)
        ans = layer[m - 1][n - 1]
        for _ in range(k):
            tele = [[INF] * n for _ in range(m)]
            for x in range(m):
                for y in range(n):
                    v = grid[x][y]
                    best = INF
                    for i in range(m):
                        for j in range(n):
                            if grid[i][j] >= v and layer[i][j] < best:
                                best = layer[i][j]
                    tele[x][y] = best
            layer = grid_relax(tele)
            ans = min(ans, layer[m - 1][n - 1])
        return ans

