class Solution:
    def minCost(self, grid, k):
        m, n = len(grid), len(grid[0])
        INF = float('inf')
        def grid_relax(start):
            dp = [row[:] for row in start]
            for i in range(m):
                for j in range(n):
                    best = dp[i][j]
                    if i > 0 and dp[i - 1][j] + grid[i][j] < best:
                        best = dp[i - 1][j] + grid[i][j]
                    if j > 0 and dp[i][j - 1] + grid[i][j] < best:
                        best = dp[i][j - 1] + grid[i][j]
                    dp[i][j] = best
            return dp
        cells = sorted(((grid[i][j], i, j) for i in range(m) for j in range(n)), reverse=True)
        base = [[INF] * n for _ in range(m)]
        base[0][0] = 0
        layer = grid_relax(base)
        ans = layer[m - 1][n - 1]
        for _ in range(k):
            # teleport relaxation via descending-value prefix minimum
            tele_by_val = {}
            run = INF
            # store min cost available for value >= threshold
            prefix = []  # list of (value, running_min)
            for v, i, j in cells:
                if layer[i][j] < run:
                    run = layer[i][j]
                prefix.append((v, run))
            # for each cell find min over values >= its value: prefix is descending by value
            # build mapping value -> best running min at the point all values >= v are seen
            import bisect
            vals = [p[0] for p in prefix]
            mins = [p[1] for p in prefix]
            tele = [[INF] * n for _ in range(m)]
            for x in range(m):
                for y in range(n):
                    v = grid[x][y]
                    # find last index where value >= v (vals descending)
                    lo, hi = 0, len(vals)
                    while lo < hi:
                        mid = (lo + hi) // 2
                        if vals[mid] >= v:
                            lo = mid + 1
                        else:
                            hi = mid
                    if lo > 0:
                        tele[x][y] = mins[lo - 1]
            layer = grid_relax(tele)
            if layer[m - 1][n - 1] < ans:
                ans = layer[m - 1][n - 1]
        return ans

