var minCost = function(grid, k) {
    const m = grid.length, n = grid[0].length;
    const INF = Infinity;
    const gridRelax = (start) => {
        const dp = start.map(r => r.slice());
        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                let best = dp[i][j];
                if (i > 0 && dp[i - 1][j] + grid[i][j] < best) best = dp[i - 1][j] + grid[i][j];
                if (j > 0 && dp[i][j - 1] + grid[i][j] < best) best = dp[i][j - 1] + grid[i][j];
                dp[i][j] = best;
            }
        }
        return dp;
    };
    const cells = [];
    for (let i = 0; i < m; i++) for (let j = 0; j < n; j++) cells.push([grid[i][j], i, j]);
    cells.sort((a, b) => b[0] - a[0]);
    let base = Array.from({length: m}, () => new Array(n).fill(INF));
    base[0][0] = 0;
    let layer = gridRelax(base);
    let ans = layer[m - 1][n - 1];
    for (let t = 0; t < k; t++) {
        const vals = [], mins = [];
        let run = INF;
        for (const [v, i, j] of cells) {
            if (layer[i][j] < run) run = layer[i][j];
            vals.push(v); mins.push(run);
        }
        const tele = Array.from({length: m}, () => new Array(n).fill(INF));
        for (let x = 0; x < m; x++) {
            for (let y = 0; y < n; y++) {
                const v = grid[x][y];
                let lo = 0, hi = vals.length;
                while (lo < hi) {
                    const mid = (lo + hi) >> 1;
                    if (vals[mid] >= v) lo = mid + 1; else hi = mid;
                }
                if (lo > 0) tele[x][y] = mins[lo - 1];
            }
        }
        layer = gridRelax(tele);
        if (layer[m - 1][n - 1] < ans) ans = layer[m - 1][n - 1];
    }
    return ans;
};
